def parse_authn_request(saml_request_encoded):
    """Parse and validate an incoming SAML AuthnRequest."""
    try:
        decoded = base64.b64decode(saml_request_encoded)
        # Try to decompress (deflate encoding)
        import zlib
        try:
            xml_string = zlib.decompress(decoded, -15)
        except zlib.error:
            xml_string = decoded

        root = etree.fromstring(xml_string)

        authn_request = {
            "id": root.get("ID"),
            "issuer": root.find("{%s}Issuer" % SAML_NAMESPACE).text if root.find("{%s}Issuer" % SAML_NAMESPACE) is not None else None,
            "acs_url": root.get("AssertionConsumerServiceURL"),
            "destination": root.get("Destination"),
            "protocol_binding": root.get("ProtocolBinding"),
        }

        return authn_request
    except Exception as e:
        print(f"Error parsing AuthnRequest: {e}")
        return None


def validate_authn_request(authn_request):
    """Validate the AuthnRequest against registered SPs."""
    if not authn_request:
        return False, "Invalid AuthnRequest"

    issuer = authn_request.get("issuer")
    if issuer not in REGISTERED_SPS:
        return False, f"Unknown Service Provider: {issuer}"

    sp_config = REGISTERED_SPS[issuer]
    acs_url = authn_request.get("acs_url")
    if acs_url and acs_url != sp_config["acs_url"]:
        return False, f"ACS URL mismatch: {acs_url}"

    return True, "Valid"


def build_saml_response(authn_request, user_info, username):
    """
    Build a SAML Response with a signed assertion.
    The assertion is signed but not encrypted - HTTPS provides transport security.
    """
    now = datetime.now(timezone.utc)
    not_on_or_after = now + timedelta(minutes=5)
    session_not_on_or_after = now + timedelta(hours=8)

    response_id = generate_id()
    assertion_id = generate_id()

    sp_entity_id = authn_request["issuer"]
    sp_config = REGISTERED_SPS[sp_entity_id]
    acs_url = authn_request.get("acs_url") or sp_config["acs_url"]
    in_response_to = authn_request.get("id", "")

    time_format = "%Y-%m-%dT%H:%M:%SZ"
    now_str = now.strftime(time_format)
    not_on_or_after_str = not_on_or_after.strftime(time_format)
    session_not_on_or_after_str = session_not_on_or_after.strftime(time_format)

    # Build the SAML Response XML
    response = etree.Element(
        "{%s}Response" % SAMLP_NAMESPACE,
        nsmap=NSMAP,
        attrib={
            "ID": response_id,
            "Version": "2.0",
            "IssueInstant": now_str,
            "Destination": acs_url,
            "InResponseTo": in_response_to,
        },
    )

    # Response Issuer
    response_issuer = etree.SubElement(response, "{%s}Issuer" % SAML_NAMESPACE)
    response_issuer.text = IDP_ENTITY_ID

    # Status
    status = etree.SubElement(response, "{%s}Status" % SAMLP_NAMESPACE)
    status_code = etree.SubElement(
        status,
        "{%s}StatusCode" % SAMLP_NAMESPACE,
        attrib={"Value": "urn:oasis:names:tc:SAML:2.0:status:Success"},
    )

    # Assertion
    assertion = etree.SubElement(
        response,
        "{%s}Assertion" % SAML_NAMESPACE,
        nsmap=NSMAP,
        attrib={
            "ID": assertion_id,
            "Version": "2.0",
            "IssueInstant": now_str,
        },
    )

    # Assertion Issuer
    assertion_issuer = etree.SubElement(assertion, "{%s}Issuer" % SAML_NAMESPACE)
    assertion_issuer.text = IDP_ENTITY_ID

    # Subject
    subject = etree.SubElement(assertion, "{%s}Subject" % SAML_NAMESPACE)
    name_id = etree.SubElement(
        subject,
        "{%s}NameID" % SAML_NAMESPACE,
        attrib={
            "Format": "urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress",
            "SPNameQualifier": sp_entity_id,
        },
    )
    name_id.text = user_info["email"]

    subject_confirmation = etree.SubElement(
        subject,
        "{%s}SubjectConfirmation" % SAML_NAMESPACE,
        attrib={"Method": "urn:oasis:names:tc:SAML:2.0:cm:bearer"},
    )
    etree.SubElement(
        subject_confirmation,
        "{%s}SubjectConfirmationData" % SAML_NAMESPACE,
        attrib={
            "InResponseTo": in_response_to,
            "NotOnOrAfter": not_on_or_after_str,
            "Recipient": acs_url,
        },
    )

    # Conditions
    conditions = etree.SubElement(
        assertion,
        "{%s}Conditions" % SAML_NAMESPACE,
        attrib={
            "NotBefore": now_str,
            "NotOnOrAfter": not_on_or_after_str,
        },
    )
    audience_restriction = etree.SubElement(
        conditions, "{%s}AudienceRestriction" % SAML_NAMESPACE
    )
    audience = etree.SubElement(
        audience_restriction, "{%s}Audience" % SAML_NAMESPACE
    )
    audience.text = sp_entity_id

    # AuthnStatement
    authn_statement = etree.SubElement(
        assertion,
        "{%s}AuthnStatement" % SAML_NAMESPACE,
        attrib={
            "AuthnInstant": now_str,
            "SessionIndex": assertion_id,
            "SessionNotOnOrAfter": session_not_on_or_after_str,
        },
    )
    authn_context = etree.SubElement(
        authn_statement, "{%s}AuthnContext" % SAML_NAMESPACE
    )
    authn_context_class_ref = etree.SubElement(
        authn_context, "{%s}AuthnContextClassRef" % SAML_NAMESPACE
    )
    authn_context_class_ref.text = (
        "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport"
    )

    # AttributeStatement
    attribute_statement = etree.SubElement(
        assertion, "{%s}AttributeStatement" % SAML_NAMESPACE
    )

    # Add user attributes
    attributes = {
        "uid": username,
        "email": user_info["email"],
        "firstName": user_info["first_name"],
        "lastName": user_info["last_name"],
        "roles": user_info["roles"],
    }

    for attr_name, attr_values in attributes.items():
        attribute = etree.SubElement(
            attribute_statement,
            "{%s}Attribute" % SAML_NAMESPACE,
            attrib={
                "Name": attr_name,
                "NameFormat": "urn:oasis:names:tc:SAML:2.0:attrname-format:basic",
            },
        )
        if not isinstance(attr_values, list):
            attr_values = [attr_values]
        for val in attr_values:
            attr_value = etree.SubElement(
                attribute, "{%s}AttributeValue" % SAML_NAMESPACE
            )
            attr_value.text = str(val)

    # Sign the assertion
    signed_response = sign_assertion(response, assertion_id)

    return signed_response


def sign_assertion(response_element, assertion_id):
    """
    Sign the SAML assertion within the response using XML Digital Signature.
    Uses enveloped signature method.
    """
    private_key = load_private_key()
    certificate = load_certificate()

    # Find the assertion element to sign
    assertion = response_element.find(".//{%s}Assertion" % SAML_NAMESPACE)

    if assertion is None:
        raise ValueError("No Assertion element found in response")

    # Sign the assertion using signxml
    signer = XMLSigner(
        method=methods.enveloped,
        signature_algorithm="rsa-sha256",
        digest_algorithm="sha256",
        c14n_algorithm="http://www.w3.org/2001/10/xml-exc-c14n#",
    )

    # Sign the assertion element
    signed_assertion = signer.sign(
        assertion,
        key=private_key,
        cert=certificate,
        reference_uri="#" + assertion_id,
    )

    # Replace the unsigned assertion with the signed one in the response
    response_element.replace(assertion, signed_assertion)

    return response_element


def build_saml_response_encoded(authn_request, user_info, username):
    """Build and base64-encode the SAML response."""
    response_element = build_saml_response(authn_request, user_info, username)
    response_xml = etree.tostring(
        response_element, xml_declaration=True, encoding="UTF-8"
    )
    return base64.b64encode(response_xml).decode("utf-8")


