@app.route("/sso", methods=["GET", "POST"])
def sso():
    """
    Single Sign-On endpoint.
    Handles both HTTP-Redirect (GET) and HTTP-POST (POST) bindings for AuthnRequest.
    """
    saml_request = None
    relay_state = ""

    if request.method == "GET":
        saml_request = request.args.get("SAMLRequest")
        relay_state = request.args.get("RelayState", "")

        if not saml_request:
            return "Missing SAMLRequest parameter", 400

        # Parse the AuthnRequest
        authn_request = parse_authn_request(saml_request)
        valid, message = validate_authn_request(authn_request)

        if not valid:
            return f"Invalid AuthnRequest: {message}", 400

        # Store in session for POST back after authentication
        session["authn_request"] = authn_request
        session["relay_state"] = relay_state
        session["saml_request_raw"] = saml_request

        # Check if user is already authenticated
        if "username" in session and "authenticated" in session:
            return process_authenticated_user(
                authn_request, session["username"], relay_state
            )

        # Show login form
        sp_name = REGISTERED_SPS.get(authn_request.get("issuer"), {}).get("name", "Unknown SP")
        return render_template_string(
            LOGIN_TEMPLATE,
            saml_request=saml_request,
            relay_state=relay_state,
            sp_name=sp_name,
            error=None,
        )

    elif request.method == "POST":
        # Could be a POST binding AuthnRequest or a login form submission
        username = request.form.get("username")
        password = request.form.get("password")
        saml_request = request.form.get("SAMLRequest")
        relay_state = request.form.get("RelayState", "")

        if username and password:
            # This is a login form submission
            authn_request = session.get("authn_request")
            relay_state = session.get("relay_state", relay_state)

            if not authn_request and saml_request:
                authn_request = parse_authn_request(saml_request)
                session["authn_request"] = authn_request
                session["relay_state"] = relay_state

            if not authn_request:
                return "Session expired. Please try again.", 400

            # Authenticate user
            user_info = authenticate_user(username, password)
            if not user_info:
                sp_name = REGISTERED_SPS.get(
                    authn_request.get("issuer"), {}
                ).get("name", "Unknown SP")
                return render_template_string(
                    LOGIN_TEMPLATE,
                    saml_request=saml_request or session.get("saml_request_raw", ""),
                    relay_state=relay_state,
                    sp_name=sp_name,
                    error="Invalid username or password",
                )

            # Mark user as authenticated
            session["username"] = username
            session["authenticated"] = True

            return process_authenticated_user(authn_request, username, relay_state)

        elif saml_request:
            # POST binding AuthnRequest
            authn_request = parse_authn_request(saml_request)
            valid, message = validate_authn_request(authn_request)

            if not valid:
                return f"Invalid AuthnRequest: {message}", 400

            session["authn_request"] = authn_request
            session["relay_state"] = relay_state
            session["saml_request_raw"] = saml_request

            if "username" in session and "authenticated" in session:
                return process_authenticated_user(
                    authn_request, session["username"], relay_state
                )

            sp_name = REGISTERED_SPS.get(
                authn_request.get("issuer"), {}
            ).get("name", "Unknown SP")
            return render_template_string(
                LOGIN_TEMPLATE,
                saml_request=saml_request,
                relay_state=relay_state,
                sp_name=sp_name,
                error=None,
            )

    return "Bad Request", 400


def process_authenticated_user(authn_request, username, relay_state):
    """Generate SAML response for an authenticated user and send to SP."""
    user_info = USERS.get(username)
    if not user_info:
        return "User not found", 404

    # Build the signed SAML response
    saml_response_encoded = build_saml_response_encoded(
        authn_request, user_info, username
    )

    acs_url = authn_request.get("acs_url") or REGISTERED_SPS.get(
        authn_request["issuer"], {}
    ).get("acs_url")

    if not acs_url:
        return "No ACS URL configured for this SP", 400

    # Send via POST binding (auto-submit form)
    return render_template_string(
        POST_BINDING_TEMPLATE,
        acs_url=acs_url,
        saml_response=saml_response_encoded,
        relay_state=relay_state,
    )


