@app.route("/idp-initiated", methods=["GET"])
def idp_initiated_sso():
    """
    IdP-initiated SSO - allows starting SSO from the IdP side
    without an AuthnRequest from the SP.
    """
    sp_entity_id = request.args.get("sp")
    relay_state = request.args.get("RelayState", "")

    if not sp_entity_id or sp_entity_id not in REGISTERED_SPS:
        return "Unknown or missing Service Provider", 400

    if "username" not in session or "authenticated" not in session:
        # Store the SP info and redirect to login
        session["idp_initiated_sp"] = sp_entity_id
        session["relay_state"] = relay_state

        # Create a minimal authn_request for IdP-initiated flow
        authn_request = {
            "id": generate_id(),
            "issuer": sp_entity_id,
            "acs_url": REGISTERED_SPS[sp_entity_id]["acs_url"],
        }
        session["authn_request"] = authn_request

        sp_name = REGISTERED_SPS[sp_entity_id]["name"]
        return render_template_string(
            LOGIN_TEMPLATE,
            saml_request="",
            relay_state=relay_state,
            sp_name=sp_name,
            error=None,
        )

    # User is already authenticated
    sp_config = REGISTERED_SPS[sp_entity_id]
    authn_request = {
        "id": generate_id(),
        "issuer": sp_entity_id,
        "acs_url": sp_config["acs_url"],
    }

    return process_authenticated_user(
        authn_request, session["username"], relay_state
    )


def create_ssl_context():
    """Create SSL context for HTTPS."""
    import ssl
    ssl_dir = os.path.join(os.path.dirname(__file__), "ssl")
    os.makedirs(ssl_dir, exist_ok=True)

    ssl_cert = os.path.join(ssl_dir, "server.crt")
    ssl_key = os.path.join(ssl_dir, "server.key")

    if not os.path.exists(ssl_cert) or not os.path.exists(ssl_key):
        # Generate self-signed SSL certificate for HTTPS
        key = rsa.generate_private_key(public_exponent=65537, key_size=2048)
        subject = issuer = x509.Name([
            x509.NameAttribute(NameOID.COMMON_NAME, "idp.internal.example.com"),
        ])
        cert = (
            x509.CertificateBuilder()
            .subject_name(subject)
            .issuer_name(issuer)
            .public_key(key.public_key())
            .serial_number(x509.random_serial_number())
            .not_valid_before(datetime.now(timezone.utc))
            .not_valid_after(datetime.now(timezone.utc) + timedelta(days=365))
            .add_extension(
                x509.SubjectAlternativeName([
                    x509.DNSName("localhost"),
                    x509.DNSName("idp.internal.example.com"),
                ]),
                critical=False,
            )
            .sign(key, hashes.SHA256())
        )

        with open(ssl_key, "wb") as f:
            f.write(key.private_bytes(
                encoding=serialization.Encoding.PEM,
                format=serialization.PrivateFormat.TraditionalOpenSSL,
                encryption_algorithm=serialization.NoEncryption(),
            ))
        with open(ssl_cert, "wb") as f:
            f.write(cert.public_bytes(serialization.Encoding.PEM))

        print("Generated SSL certificate for HTTPS.")

    context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
    context.load_cert_chain(ssl_cert, ssl_key)
    return context


if __name__ == "__main__":
    # Generate IdP signing certificate if not exists
    generate_self_signed_cert()

